-- Database-backed curriculum and standalone game content metadata/security.
--
-- Content payloads remain JSON bundles. Rendering, mechanics, scoring,
-- progress, achievements, and bundled asset resolution remain app-owned.

BEGIN;

ALTER TABLE public.content_items
  ADD COLUMN IF NOT EXISTS editorial_status text NOT NULL DEFAULT 'draft',
  ADD COLUMN IF NOT EXISTS is_startable boolean NOT NULL DEFAULT true,
  ADD COLUMN IF NOT EXISTS content_version bigint NOT NULL DEFAULT 1,
  ADD COLUMN IF NOT EXISTS published_at timestamp with time zone;

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1
    FROM pg_constraint
    WHERE conname = 'content_items_editorial_status_check'
      AND conrelid = 'public.content_items'::regclass
  ) THEN
    ALTER TABLE public.content_items
      ADD CONSTRAINT content_items_editorial_status_check
      CHECK (editorial_status IN ('draft', 'reviewed', 'published'));
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM pg_constraint
    WHERE conname = 'content_items_content_version_positive'
      AND conrelid = 'public.content_items'::regclass
  ) THEN
    ALTER TABLE public.content_items
      ADD CONSTRAINT content_items_content_version_positive
      CHECK (content_version > 0);
  END IF;
END
$$;

COMMENT ON TABLE public.content_items IS
  'Versioned, exact-language MVP content bundles. App code owns rendering, mechanics, scoring, progress, achievements, and bundled asset resolution.';
COMMENT ON COLUMN public.content_items.editorial_status IS
  'Editorial lifecycle. Child clients may read only published, active rows.';
COMMENT ON COLUMN public.content_items.is_startable IS
  'Whether the content bundle can currently launch; false content may still be shown as locked or coming soon.';
COMMENT ON COLUMN public.content_items.content_version IS
  'Monotonically increasing bundle revision used for client cache invalidation.';
COMMENT ON COLUMN public.content_items.published_at IS
  'Publication timestamp when known; nullable for migrated historical content.';

CREATE INDEX IF NOT EXISTS idx_content_items_published_language_order
ON public.content_items(language_code, sort_order, content_type, slug)
INCLUDE (content_version, updated_at, is_startable)
WHERE is_active = true AND editorial_status = 'published';

CREATE OR REPLACE FUNCTION public.set_content_items_updated_at()
RETURNS trigger
LANGUAGE plpgsql
SET search_path = pg_catalog
AS $$
BEGIN
  NEW.updated_at = timezone('utc'::text, now());
  RETURN NEW;
END;
$$;

ALTER TABLE public.content_items ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS content_items_published_select
ON public.content_items;

CREATE POLICY content_items_published_select
ON public.content_items
FOR SELECT
TO anon, authenticated
USING (is_active = true AND editorial_status = 'published');

-- Data API grants are intentionally separate from row visibility policies.
-- Child-facing roles can read published rows but cannot author or publish data.
REVOKE ALL PRIVILEGES ON TABLE public.content_items
FROM PUBLIC, anon, authenticated;
GRANT SELECT ON TABLE public.content_items TO anon, authenticated;

GRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.content_items
TO service_role;

REVOKE ALL PRIVILEGES ON FUNCTION public.set_content_items_updated_at()
FROM PUBLIC, anon, authenticated;
GRANT EXECUTE ON FUNCTION public.set_content_items_updated_at()
TO service_role;

