se,"readiness":"placeholder","items":[{"id":"story-question","mechanic":"mini_quiz","order":1,"word":"Laba ekifaananyi","translation":"Look at the picture","imageKey":"culture.jpg"}]}]},{"id":"practice-mix","order":5,"stageNumber":5,"title":"Practice Mix","description":"Review words after a few lessons are complete.","imageKey":"african-patterns.png","status":"locked","readiness":"placeholder","estimatedMinutes":5,"lessonCount":1,"isPractice":true,"isLocked":true,"mechanics":["practice_mix"],"learningGoals":["Review words from finished stages","Practice words that need another try","Come back to words over time"],"placeholderMessage":"Practice Mix will unlock after enough lessons are completed in the future.","lessons":[{"id":"review-first-words","title":"First Words Review","description":"Review words after enough lessons are complete.","mechanic":"practice_mix","order":1,"isStartable":false,"readiness":"placeholder","items":[{"id":"first-words-review","mechanic":"practice_mix","order":1,"word":"Webale","translation":"Thank you","imageKey":"learning-beginner.jpg"}]}]}]}$content$::jsonb,
