VALUES (
  'lg', 'learning_game', 'starter', 'Luganda Learning',
  $content${"stages":[{"id":1,"order":1,"title":"Beginner","description":"Learn basic Luganda words and phrases","isLocked":false,"requiredScore":0,"color":"#4F85E6","image":"coin.png","levels":[{"id":1,"order":1,"title":"Greetings","isLocked":false,"words":[{"id":"lg-learning-stage-1-level-1-word-1","order":1,"targetText":"Oli otya","english":"How are you","example":"Oli otya leero?","exampleTranslation":"How are you today?","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-1-level-1-word-2","order":2,"targetText":"Bulungi","english":"Good/Fine","example":"Ndi bulungi, webale.","exampleTranslation":"I'm fine, thank you.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-1-level-1-word-3","order":3,"targetText":"Webale","english":"Thank you","example":"Webale nnyo!","exampleTranslation":"Thank you very much!","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-1-level-1-word-4","order":4,"targetText":"Ssebo","english":"Sir","example":"Ssebo, nnyamba.","exampleTranslation":"Sir, help me.","audio":"correct.mp3","image":"learning-beginner.jpg"}]},{"id":2,"order":2,"title":"People","isLocked":false,"words":[{"id":"lg-learning-stage-1-level-2-word-1","order":1,"targetText":"Omukazi","english":"Woman","example":"Omukazi oyo mulungi nnyo.","exampleTranslation":"That woman is very beautiful.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-1-level-2-word-2","order":2,"targetText":"Omusajja","english":"Man","example":"Omusajja oyo mugumikiriza.","exampleTranslation":"That man is patient.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-1-level-2-word-3","order":3,"targetText":"Omwana","english":"Child","example":"Omwana oyo musanyufu nnyo.","exampleTranslation":"That child is very happy.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-1-level-2-word-4","order":4,"targetText":"Abawala","english":"Girls","example":"Abawala bali basoma.","exampleTranslation":"Those girls are studying.","audio":"correct.mp3","image":"learning-beginner.jpg"}]}]},{"id":2,"order":2,"title":"Elementary","description":"Basic objects and everyday items","isLocked":true,"requiredScore":50,"color":"#6C5CE7","image":"coin.png","levels":[{"id":3,"order":1,"title":"Objects","isLocked":true,"words":[{"id":"lg-learning-stage-2-level-3-word-1","order":1,"targetText":"Amazzi","english":"Water","example":"Amazzi gano mangi.","exampleTranslation":"This water is a lot.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-2-level-3-word-2","order":2,"targetText":"Emmere","english":"Food","example":"Emmere eno nnungi.","exampleTranslation":"This food is delicious.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-2-level-3-word-3","order":3,"targetText":"Ennyumba","english":"House","example":"Ennyumba yange nnungi.","exampleTranslation":"My house is beautiful.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-2-level-3-word-4","order":4,"targetText":"Ekitabo","english":"Book","example":"Ekitabo kino kirungi.","exampleTranslation":"This book is good.","audio":"correct.mp3","image":"learning-beginner.jpg"}]},{"id":4,"order":2,"title":"Places","isLocked":true,"words":[{"id":"lg-learning-stage-2-level-4-word-1","order":1,"targetText":"Ekibuga","english":"City","example":"Ekibuga kya Kampala kinene.","exampleTranslation":"Kampala city is big.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-2-level-4-word-2","order":2,"targetText":"Ekyalo","english":"Village","example":"Ekyalo kyange kirungi.","exampleTranslation":"My village is beautiful.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-2-level-4-word-3","order":3,"targetText":"Essomero","english":"School","example":"Essomero lino linene.","exampleTranslation":"This school is big.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-2-level-4-word-4","order":4,"targetText":"Eddwaliro","english":"Hospital","example":"Eddwaliro lisangibwa ku kasozi.","exampleTranslation":"The hospital is located on the hill.","audio":"correct.mp3","image":"learning-beginner.jpg"}]}]},{"id":3,"order":3,"title":"Intermediate","description":"Actions and descriptions","isLocked":true,"requiredScore":90,"color":"#00B894","image":"coin.png","levels":[{"id":5,"order":1,"title":"Verbs","isLocked":true,"words":[{"id":"lg-learning-stage-3-level-5-word-1","order":1,"targetText":"Okukyala","english":"To visit","example":"Njagala okukyala mu kyalo kyange.","exampleTranslation":"I want to visit my village.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-3-level-5-word-2","order":2,"targetText":"Okuyiga","english":"To learn","example":"Njagala okuyiga Oluganda.","exampleTranslation":"I want to learn Luganda.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-3-level-5-word-3","order":3,"targetText":"Okulya","english":"To eat","example":"Tujja kulya emmere.","exampleTranslation":"We will eat food.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-3-level-5-word-4","order":4,"targetText":"Okunywa","english":"To drink","example":"Njagala okunywa amazzi.","exampleTranslation":"I want to drink water.","audio":"correct.mp3","image":"learning-beginner.jpg"}]},{"id":6,"order":2,"title":"Adjectives","isLocked":true,"words":[{"id":"lg-learning-stage-3-level-6-word-1","order":1,"targetText":"Bulungi","english":"Good","example":"Kirungi nnyo.","exampleTranslation":"It is very good.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-3-level-6-word-2","order":2,"targetText":"Bubi","english":"Bad","example":"Embeera mbi.","exampleTranslation":"The situation is bad.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-3-level-6-word-3","order":3,"targetText":"Kinene","english":"Big","example":"Ennyumba nnene.","exampleTranslation":"The house is big.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-3-level-6-word-4","order":4,"targetText":"Kitono","english":"Small","example":"Akatunda katono.","exampleTranslation":"The fruit is small.","audio":"correct.mp3","image":"learning-beginner.jpg"}]}]},{"id":4,"order":4,"title":"Advanced","description":"Nature and environment","isLocked":true,"requiredScore":130,"color":"#FF7675","image":"coin.png","levels":[{"id":7,"order":1,"title":"Nature","isLocked":true,"words":[{"id":"lg-learning-stage-4-level-7-word-1","order":1,"targetText":"Eggulu","english":"Sky","example":"Eggulu lino bbululu.","exampleTranslation":"The sky is blue.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-4-level-7-word-2","order":2,"targetText":"Emmunyeenye","english":"Star","example":"Emmunyeenye nyingi ziri mu ggulu.","exampleTranslation":"There are many stars in the sky.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-4-level-7-word-3","order":3,"targetText":"Omusana","english":"Sun","example":"Omusana gwaka nnyo leero.","exampleTranslation":"The sun is very hot today.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-4-level-7-word-4","order":4,"targetText":"Omwezi","english":"Moon","example":"Omwezi gwaka ekiro.","exampleTranslation":"The moon shines at night.","audio":"correct.mp3","image":"learning-beginner.jpg"}]},{"id":8,"order":2,"title":"Environment","isLocked":true,"words":[{"id":"lg-learning-stage-4-level-8-word-1","order":1,"targetText":"Olukalu","english":"Land","example":"Olukalu luno lugimu.","exampleTranslation":"This land is fertile.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-4-level-8-word-2","order":2,"targetText":"Ekibira","english":"Forest","example":"Ekibira kino kinene.","exampleTranslation":"This forest is big.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-4-level-8-word-3","order":3,"targetText":"Enyanja","english":"Lake","example":"Enyanja Victoria nnene.","exampleTranslation":"Lake Victoria is big.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-4-level-8-word-4","order":4,"targetText":"Olusozi","english":"Mountain","example":"Olusozi luno luwanvu.","exampleTranslation":"This mountain is tall.","audio":"correct.mp3","image":"learning-beginner.jpg"}]}]},{"id":5,"order":5,"title":"Expert","description":"Complex concepts and expressions","isLocked":true,"requiredScore":170,"color":"#A29BFE","image":"coin.png","levels":[{"id":9,"order":1,"title":"Time Expressions","isLocked":true,"words":[{"id":"lg-learning-stage-5-level-9-word-1","order":1,"targetText":"Leero","english":"Today","example":"Leero nnagenda mu kibuga.","exampleTranslation":"Today I went to the city.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-5-level-9-word-2","order":2,"targetText":"Enkya","english":"Tomorrow","example":"Enkya tugenda mu ssomero.","exampleTranslation":"Tomorrow we go to school.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-5-level-9-word-3","order":3,"targetText":"Jjo","english":"Yesterday","example":"Jjo twalabye film.","exampleTranslation":"Yesterday we watched a film.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-5-level-9-word-4","order":4,"targetText":"Essawa","english":"Hour/Time","example":"Essawa mmeka?","exampleTranslation":"What time is it?","audio":"correct.mp3","image":"learning-beginner.jpg"}]},{"id":10,"order":2,"title":"Expressions","isLocked":true,"words":[{"id":"lg-learning-stage-5-level-10-word-1","order":1,"targetText":"Nsanyuse okukulaba","english":"Nice to meet you","example":"Nsanyuse okukulaba nate.","exampleTranslation":"Nice to meet you again.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-5-level-10-word-2","order":2,"targetText":"Tewali mutawaana","english":"No problem","example":"Tewali mutawaana, nsobola okukuyamba.","exampleTranslation":"No problem, I can help you.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-5-level-10-word-3","order":3,"targetText":"Nkwagala","english":"I love you","example":"Nkwagala nnyo.","exampleTranslation":"I love you very much.","audio":"correct.mp3","image":"learning-beginner.jpg"},{"id":"lg-learning-stage-5-level-10-word-4","order":4,"targetText":"Simanyi","english":"I don't know","example":"Simanyi luganda lungi.","exampleTranslation":"I don't know good Luganda.","audio":"correct.mp3","image":"learning-beginner.jpg"}]}]}]}$content$::jsonb,
