  'lg', 'card_game', 'cards', 'Buganda Cultural Cards',
  $content${"title":"Buganda Cultural Cards","items":[{"id":"card-lg-001","value":"Kabaka","info":"The King of Buganda, one of the most powerful traditional monarchs in Uganda.","imageSymbol":"👑","order":1},{"id":"card-lg-002","value":"Lubiri","info":"The royal palace of the Kabaka of Buganda located in Mengo, Kampala.","imageSymbol":"🏰","order":2},{"id":"card-lg-003","value":"Matoke","info":"Steamed green bananas, a staple food in Buganda cuisine.","imageSymbol":"🍌","order":3},{"id":"card-lg-004","value":"Kanzu","info":"Traditional white robe worn by Baganda men, especially during ceremonies.","imageSymbol":"👘","order":4},{"id":"card-lg-005","value":"Gomesi","info":"A colorful floor-length dress worn by Baganda women during ceremonies.","imageSymbol":"👗","order":5},{"id":"card-lg-006","value":"Engoma","info":"Traditional drums used in Kiganda music and royal ceremonies.","imageSymbol":"🥁","order":6},{"id":"card-lg-007","value":"Lukiiko","info":"The parliament or council of the Buganda Kingdom.","imageSymbol":"🏛️","order":7},{"id":"card-lg-008","value":"Olugero","info":"Traditional fables and stories that teach moral lessons in Buganda culture.","imageSymbol":"📚","order":8},{"id":"card-lg-009","value":"Bakisimba","info":"A traditional Baganda dance performed at cultural celebrations.","imageSymbol":"💃","order":9},{"id":"card-lg-010","value":"Mweso","info":"A traditional board game played throughout Uganda, especially in Buganda.","imageSymbol":"🎮","order":10},{"id":"card-lg-011","value":"Endere","info":"A traditional flute used in Kiganda music.","imageSymbol":"🎵","order":11},{"id":"card-lg-012","value":"Amadinda","info":"A xylophone-like instrument with wooden keys used in traditional music.","imageSymbol":"🎹","order":12},{"id":"card-lg-013","value":"Ensi","info":"The traditional territories or counties of Buganda Kingdom.","imageSymbol":"🗺️","order":13},{"id":"card-lg-014","value":"Namasole","info":"The title given to the mother of the Kabaka (King) of Buganda.","imageSymbol":"👸","order":14},{"id":"card-lg-015","value":"Katikkiro","info":"The prime minister or chief minister of the Buganda Kingdom.","imageSymbol":"👔","order":15},{"id":"card-lg-016","value":"Ssabasajja","info":"An honorific title for the Kabaka, meaning 'Chief of Men'.","imageSymbol":"🤴","order":16},{"id":"card-lg-017","value":"Kasubi","info":"The royal burial grounds where Buganda kings are laid to rest.","imageSymbol":"⚱️","order":17},{"id":"card-lg-018","value":"Bulungi Bwansi","info":"Traditional community service practice in Buganda culture.","imageSymbol":"🌱","order":18},{"id":"card-lg-019","value":"Empagi","info":"The traditional pillars that support the Buganda social structure.","imageSymbol":"🏗️","order":19},{"id":"card-lg-020","value":"Akendo","info":"Traditional walking stick symbolizing authority in Buganda culture.","imageSymbol":"🦯","order":20},{"id":"card-lg-021","value":"Omuziro","info":"Clan totems that are sacred and respected in Buganda tradition.","imageSymbol":"🐘","order":21},{"id":"card-lg-022","value":"Ddamula","info":"The royal scepter, a symbol of the Kabaka's authority.","imageSymbol":"🔱","order":22},{"id":"card-lg-023","value":"Luwombo","info":"A traditional Buganda dish of meat stewed in banana leaves.","imageSymbol":"🍲","order":23},{"id":"card-lg-024","value":"Entebbe","info":"A historic location in Buganda that means 'seat' or 'chair' in Luganda.","imageSymbol":"🪑","order":24},{"id":"card-lg-025","value":"Embaga","info":"Traditional festivities or celebrations in Buganda culture.","imageSymbol":"🎉","order":25},{"id":"card-lg-026","value":"Enkula","info":"Special beads worn by members of the royal family.","imageSymbol":"📿","order":26},{"id":"card-lg-027","value":"Enseenene","info":"Grasshoppers, a traditional delicacy in Buganda cuisine.","imageSymbol":"🦗","order":27},{"id":"card-lg-028","value":"Muganda","info":"A person belonging to the Baganda ethnic group.","imageSymbol":"👨","order":28},{"id":"card-lg-029","value":"Ssaabasajja","info":"Royal title for the Kabaka meaning 'Chief of Chiefs'.","imageSymbol":"👑","order":29},{"id":"card-lg-030","value":"Namulondo","info":"The royal throne of the Buganda Kingdom.","imageSymbol":"👑","order":30},{"id":"card-lg-031","value":"Kyabazinga","info":"A royal title in some kingdoms neighboring Buganda.","imageSymbol":"👑","order":31},{"id":"card-lg-032","value":"Oluganda","info":"The Luganda language, spoken by the Baganda people.","imageSymbol":"🗣️","order":32},{"id":"card-lg-033","value":"Barkcloth","info":"Traditional fabric made from the Mutuba tree, used for ceremonies.","imageSymbol":"🧵","order":33},{"id":"card-lg-034","value":"Okukyala","info":"Traditional visiting practices in Buganda culture.","imageSymbol":"🚶","order":34},{"id":"card-lg-035","value":"Nankere","info":"A small drum in the ensemble of Kiganda music.","imageSymbol":"🪘","order":35},{"id":"card-lg-036","value":"Masiro","info":"Royal tombs or burial places for Buganda royalty.","imageSymbol":"🏛️","order":36},{"id":"card-lg-037","value":"Ekyoto","info":"The traditional fireplace where families gather for stories.","imageSymbol":"🔥","order":37},{"id":"card-lg-038","value":"Entamu","info":"Traditional ceremonial spears used in Buganda rituals.","imageSymbol":"🗡️","order":38},{"id":"card-lg-039","value":"Okuggya Omwana","info":"Baby naming ceremony in Buganda culture.","imageSymbol":"👶","order":39},{"id":"card-lg-040","value":"Okwanjula","info":"Traditional introduction ceremony before marriage in Buganda.","imageSymbol":"💍","order":40},{"id":"card-lg-041","value":"Kaggwa","info":"A legendary figure in Buganda history and culture.","imageSymbol":"🦸","order":41},{"id":"card-lg-042","value":"Musambwa","info":"Ancestral spirits venerated in traditional Buganda beliefs.","imageSymbol":"👻","order":42},{"id":"card-lg-043","value":"Kawulugumo","info":"A mythical creature in Buganda folklore.","imageSymbol":"🐲","order":43},{"id":"card-lg-044","value":"Ekitiibwa","info":"Honor and respect, a core value in Buganda culture.","imageSymbol":"🙏","order":44},{"id":"card-lg-045","value":"Akasiimo","info":"Traditional gift-giving practice in Buganda.","imageSymbol":"🎁","order":45},{"id":"card-lg-046","value":"Obusinga","info":"Royal clan lineages in Buganda Kingdom.","imageSymbol":"👪","order":46},{"id":"card-lg-047","value":"Ensimbi","info":"Traditional cowrie shells once used as currency.","imageSymbol":"🐚","order":47}]}$content$::jsonb,
