  sort_order = EXCLUDED.sort_order,
  is_active = EXCLUDED.is_active,
  editorial_status = EXCLUDED.editorial_status,
  is_startable = EXCLUDED.is_startable,
  content_version = EXCLUDED.content_version,
  published_at = EXCLUDED.published_at;

-- These rows were seeded by earlier production migrations. Publish only the
-- verified Luganda story menu and story records already in the database.
UPDATE public.content_items
SET
  is_active = true,
  editorial_status = 'published',
  is_startable = true,
  content_version = GREATEST(content_version, 1),
  published_at = COALESCE(
    published_at,
    TIMESTAMPTZ '2026-07-14 18:23:26+00'
  )
WHERE language_code = 'lg'
  AND (
    (content_type = 'child_menu' AND slug = 'stories')
    OR (
      content_type = 'story'
      AND slug IN (
        'kintu',
        'mwanga',
        'kasubi-tombs',
        'walumbe',
        'ssezibwa',
        'millet',
        'kasokambirye',
        'fig-tree'
      )
    )
  );

-- The known Runyankole rows are placeholders or incomplete samples. Preserve
-- them for editorial work, but never expose or launch them in child clients.
UPDATE public.content_items
SET
  editorial_status = 'draft',
  is_startable = false,
  published_at = NULL
WHERE language_code = 'nyn'
  AND (content_type, slug) IN (
    ('child_menu', 'games'),
    ('child_menu', 'stories'),
    ('learning_game', 'starter'),
    ('word_game', 'levels'),
    ('counting_game', 'stages'),
    ('story', 'nyn-sample-morning-greeting')
  );

COMMIT;
